import{_ as a,c as e,o as m,b as t}from"./app.aa61b5f3.js";const d='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 8-9","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 8-9","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-02-05T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/3/8-9/index.md"}',i={},p=t('<div class="stanza"><a href="#s3.8" id="s3.8" class="num">3.8</a><div class="sans"><p>\u090F\u0935\u092E\u092F\u092E\u093E\u0938\u093E\u0926\u093F\u0924\u0938\u0939\u091C\u0935\u093F\u0926\u094D\u092F\u0903\u2014</p><blockquote><p><strong>\u091C\u093E\u0917\u094D\u0930\u0926\u094D\u0926\u094D\u0935\u093F\u0924\u0940\u092F\u0915\u0930\u0903\u0965\u096E\u0965</strong></p></blockquote><p>\u0932\u092C\u094D\u0927\u094D\u0935\u093E\u092A\u093F \u0936\u0941\u0926\u094D\u0927\u0935\u093F\u0926\u094D\u092F\u093E\u0902 \u0924\u0926\u0948\u0915\u0927\u094D\u092F\u0935\u094D\u092F\u093E\u092A\u094D\u0924\u094C \u091C\u093E\u0917\u0930\u0942\u0915\u0903 \u092A\u0942\u0930\u094D\u0923\u0935\u093F\u092E\u0930\u094D\u0936\u093E\u0924\u094D\u092E\u0915\u0938\u094D\u0935\u093E\u0939\u0928\u094D\u0924\u093E\u092A\u0947\u0915\u094D\u0937\u092F\u093E \u092F\u0926\u094D\u0926\u094D\u0935\u093F\u0924\u0940\u092F\u092E\u093F\u0926\u0928\u094D\u0924\u093E\u0935\u092E\u0943\u0936\u094D\u092F\u0902 \u0935\u0947\u0926\u094D\u092F\u093E\u0935\u092D\u093E\u0938\u093E\u0924\u094D\u092E\u0915\u0902 \u091C\u0917\u0924\u094D\u0924\u0924\u094D\u0915\u0930\u094B \u0930\u0936\u094D\u092E\u093F\u0930\u094D\u092F\u0938\u094D\u092F \u0924\u0925\u093E\u0935\u093F\u0927\u094B \u092D\u0935\u0924\u093F\u0964 \u0935\u093F\u0936\u094D\u0935\u092E\u0938\u094D\u092F \u0938\u094D\u0935\u0926\u0940\u0927\u093F\u0924\u093F\u0915\u0932\u094D\u092A\u0902 \u0938\u094D\u092B\u0941\u0930\u0924\u0940\u0924\u094D\u092F\u0930\u094D\u0925\u0903\u0964 \u092F\u0925\u094B\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092D\u0948\u0930\u0935\u0947</p><blockquote><p>\u092F\u0924\u094D\u0930 \u092F\u0924\u094D\u0930\u093E\u0915\u094D\u0937\u092E\u093E\u0930\u094D\u0917\u0947\u0923 \u091A\u0948\u0924\u0928\u094D\u092F\u0902 \u0935\u094D\u092F\u091C\u094D\u092F\u0924\u0947 \u0935\u093F\u092D\u094B\u0903\u0964<br> \u0924\u0938\u094D\u092F \u0924\u0928\u094D\u092E\u093E\u0924\u094D\u0930\u0927\u0930\u094D\u092E\u093F\u0924\u094D\u0935\u093E\u091A\u094D\u091A\u093F\u0932\u094D\u0932\u092F\u093E\u0926\u094D\u092D\u0930\u093F\u0924\u093E\u0924\u094D\u092E\u0924\u093E\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u0938\u0930\u094D\u0935\u092E\u0919\u094D\u0917\u0932\u093E\u092F\u093E\u092E\u092A\u093F</p><blockquote><p>\u0936\u0915\u094D\u0924\u093F\u0936\u094D\u091A \u0936\u0915\u094D\u0924\u093F\u092E\u093E\u0902\u0936\u094D\u091A\u0948\u0935 \u092A\u0926\u093E\u0930\u094D\u0925\u0926\u094D\u0935\u092F\u092E\u0941\u091A\u094D\u092F\u0924\u0947\u0964<br> \u0936\u0915\u094D\u0924\u092F\u094B\u093D\u0938\u094D\u092F \u091C\u0917\u0924\u094D\u0915\u0943\u0924\u094D\u0938\u094D\u0928\u0902 \u0936\u0915\u094D\u0924\u093F\u092E\u093E\u0902\u0938\u094D\u0924\u0941 \u092E\u0939\u0947\u0936\u094D\u0935\u0930\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u096E\u0965</p></div><hr><div class="trans"><p>Evamayam\u0101s\u0101ditasahajavidya\u1E25\u2014</p><blockquote><p><strong>J\u0101graddvit\u012Byakara\u1E25||8||</strong></p></blockquote><p>Labdhv\u0101pi \u015Buddhavidy\u0101\u1E41 tadaikadhyavy\u0101ptau j\u0101gar\u016Bka\u1E25 p\u016Br\u1E47avimar\u015B\u0101tmakasv\u0101hant\u0101pek\u1E63ay\u0101 yaddvit\u012Byamidant\u0101vam\u1E5B\u015Bya\u1E41 vedy\u0101vabh\u0101s\u0101tmaka\u1E41 jagattatkaro ra\u015Bmiryasya tath\u0101vidho bhavati| Vi\u015Bvamasya svad\u012Bdhitikalpa\u1E41 sphurat\u012Btyartha\u1E25| Yathokta\u1E41 \u015Br\u012Bvij\xF1\u0101nabhairave</p><blockquote><p>Yatra yatr\u0101k\u1E63am\u0101rge\u1E47a caitanya\u1E41 vyajyate vibho\u1E25|<br> Tasya tanm\u0101tradharmitv\u0101ccillay\u0101dbharit\u0101tmat\u0101||</p></blockquote><p>iti| \u015Ar\u012Bsarvama\u1E45gal\u0101y\u0101mapi</p><blockquote><p>\u015Aakti\u015Bca \u015Baktim\u0101\u1E41\u015Bcaiva pad\u0101rthadvayamucyate|<br> \u015Aaktayo&#39;sya jagatk\u1E5Btsna\u1E41 \u015Baktim\u0101\u1E41stu mahe\u015Bvara\u1E25||</p></blockquote><p>iti||8||</p></div><hr><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u0442\u043E\u0442 <em>(ayam)</em>, \u043A\u0442\u043E \u0434\u043E\u0441\u0442\u0438\u0433 \u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F <em>(\u0101s\u0101dita-sahaja-vidya\u1E25)</em>\u2014</p><blockquote><p><strong>[Yog\u012B, \u0434\u043E\u0441\u0442\u0438\u0433\u0448\u0438\u0439 Sahajavidy\u0101, \u0438\u043B\u0438 \u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u043D\u044B\u043C \u0438 \u0431\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u043C <em>(j\u0101grat)</em>, [\u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A] \u0432\u0442\u043E\u0440\u043E\u0439, [\u0442.\u0435. &quot;\u043C\u0438\u0440&quot;] <em>(dvit\u012Bya)</em>, [\u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043A\u0430\u043A [\u0435\u0433\u043E] \u0441\u0438\u044F\u043D\u0438\u0435 \u0441\u0432\u0435\u0442\u0430 <em>(kara\u1E25)</em>||8||</strong></p></blockquote><p>\u0414\u0430\u0436\u0435 <em>(api)</em> \u043F\u043E\u0441\u043B\u0435 \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u044F <em>(labdhv\u0101)</em> \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F <em>(\u015Buddha-vidy\u0101m)</em>, \u043F\u0440\u0438 \u043E\u0432\u043B\u0430\u0434\u0435\u043D\u0438\u0438 <em>(vy\u0101ptau)</em> \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0435\u0439 <em>(aikadhya)</em> \u043D\u0430 \u043D\u0435\u043C --\u0442.\u0435. \u0427\u0438\u0441\u0442\u043E\u043C \u0417\u043D\u0430\u043D\u0438\u0438-- <em>(tad)</em>, [Yog\u012B \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F] \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u043D\u044B\u043C \u0438 \u0431\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u043C <em>(j\u0101gar\u016Bka\u1E25)</em>. \u0427\u0442\u043E \u043A\u0430\u0441\u0430\u0435\u0442\u0441\u044F <em>(apek\u1E63ay\u0101)</em> \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(sva)</em> (\u0447\u0443\u0432\u0441\u0442\u0432\u0430) \u0421\u0435\u0431\u044F --\u0447\u0430\u0441\u0442\u0438 Aham, \u0438\u043B\u0438 \u042F-- <em>(ahant\u0101)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u0438\u0437 <em>(\u0101tmaka)</em> \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0439 <em>(p\u016Br\u1E47a)</em> Vimar\u015Ba --\u0442.\u0435. \u015Aakti-- <em>(vimar\u015Ba)</em>, \u0442\u043E\u0433\u043E, \u0447\u0442\u043E <em>(yad)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0432\u0442\u043E\u0440\u044B\u043C <em>(dvit\u012Byam)</em>, [\u043A\u043E\u0442\u043E\u0440\u043E\u0435] \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F <em>(avam\u1E5B\u015Byam)</em> \u043A\u0430\u043A \u042D\u0442\u043E\u0441\u0442\u044C --\u0447\u0430\u0441\u0442\u044C Idam, \u0438\u043B\u0438 \u042D\u0442\u043E-- <em>(idant\u0101)</em>, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0435\u0441\u044F <em>(avabh\u0101sa-\u0101tmakam)</em> \u043A\u0430\u043A \u043E\u0431\u044A\u0435\u043A\u0442 --\u0434\u043B\u044F \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0421\u0443\u0431\u044A\u0435\u043A\u0442\u0430, \u0438\u043B\u0438 \u042F-- <em>(vedya)</em>, [\u043A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F,] \u043C\u0438\u0440 <em>(jagat)</em>... [\u0438] \u044D\u0442\u043E <em>(tad)</em> [\u0435\u0441\u0442\u044C] \u0435\u0433\u043E <em>(yasya)</em> \u0441\u0438\u044F\u043D\u0438\u0435 \u0441\u0432\u0435\u0442\u0430 <em>(kara\u1E25)</em> [\u0438\u043B\u0438] \u0432\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u0438\u044F <em>(ra\u015Bmi\u1E25)</em>. \u041E\u043D --\u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B--\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(bhavati)</em> \u0442\u0430\u043A\u043E\u0432\u044B\u043C --\u0442.\u0435. \u043A\u0430\u043A\u043E\u0439 \u043E\u043D \u0435\u0441\u0442\u044C-- <em>(tath\u0101vidha\u1E25)</em>|</p><p>[\u0412 \u043E\u0431\u0449\u0435\u043C,] \u0435\u0433\u043E <em>(asya)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F <em>(vi\u015Bvam)</em> \u0441\u0438\u044F\u0435\u0442 \u0432\u043E\u0432\u043D\u0435 <em>(sphurati)</em> \u043A\u0430\u043A <em>(kalpam)</em> \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 <em>(sva)</em> \u0432\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u0438\u0435 <em>(d\u012Bdhiti)</em>. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 <em>(iti artha\u1E25)</em><sup>2</sup>|</p><p>\u041A\u0430\u043A <em>(yath\u0101)</em> \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u043C Vij\xF1\u0101nabhairava <em>(\u015Br\u012B-vij\xF1\u0101nabhairave)</em>:</p><blockquote><p>&quot;\u0412 \u043A\u0430\u043A\u043E\u0439 \u0431\u044B \u0432\u0435\u0449\u0438 --\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0433\u043E\u043B\u0443\u0431\u043E\u043C, \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0438 \u0438 \u043F\u0440.-- <em>(yatra yatra)</em> Caitanya, \u0438\u043B\u0438 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(caitanyam)</em> \u0412\u0435\u0437\u0434\u0435\u0441\u0443\u0449\u0435\u0433\u043E --\u0442.\u0435. Parabhairava, \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430-- <em>(vibho\u1E25)</em> (\u043D\u0438) \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(vyajyate)</em>, \u0438 \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u0430 \u0432\u0435\u0449\u044C --\u0442.\u0435. \u0433\u043E\u043B\u0443\u0431\u043E\u0439, \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u0438 \u043F\u0440.-- \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u0443\u0435\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u042D\u0442\u0438\u043C --Caitanya \u0412\u0435\u0437\u0434\u0435\u0441\u0443\u0449\u0435\u0433\u043E-- <em>(tasya tad-m\u0101tra-dharmitv\u0101)</em>, [\u0442\u043E,] \u0447\u0435\u0440\u0435\u0437 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(lay\u0101t)</em> \u0432 Cit --\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0438, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0432\u0435\u0437\u0434\u0435\u0441\u0443\u0449\u0435-- <em>(cit)</em>, [\u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043D\u0430\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E <em>(\u0101tmat\u0101)</em> \u043F\u043E\u043B\u043D\u043E\u0442\u044B <em>(bharita... iti)</em> --\u043A\u043E\u0440\u043E\u0447\u0435, \u043E\u043D \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u0442 \u043F\u043E\u043B\u043D\u043E\u0442\u0443 Parabhairava, \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430--<sup>3</sup>&quot;||</p></blockquote><p>\u0422\u0430\u043A\u0436\u0435 <em>(api)</em>, \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u0439 Sarvama\u1E45gal\u0101 <em>(\u015Br\u012B-sarvama\u1E45gal\u0101y\u0101m)</em>:</p><blockquote><p>&quot;\u0413\u043E\u0432\u043E\u0440\u044F\u0442, \u0447\u0442\u043E \u0438\u043C\u0435\u0435\u0442\u0441\u044F <em>(ucyate)</em> \u0442\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u0434\u0432\u0435 <em>(dvayam)</em> \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 <em>(pad\u0101rtha)</em>, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u015Aakti --\u0421\u0438\u043B\u0430-- <em>(\u015Bakti\u1E25)</em> \u0438 <em>(ca... ca)</em> \u041E\u0431\u043B\u0430\u0434\u0430\u0442\u0435\u043B\u044C \u015Aakti <em>(\u015Baktim\u0101n)</em>. \u041E\u0431\u043B\u0430\u0434\u0430\u0442\u0435\u043B\u044C \u015Aakti <em>(\u015Baktim\u0101n)</em> [\u2014 \u044D\u0442\u043E] \u0412\u0435\u043B\u0438\u043A\u0438\u0439 <em>(mah\u0101)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u044C <em>(\u012B\u015Bvara\u1E25)</em>, \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E <em>(tu)</em> --\u0442.\u0435. \u015Aiva--, [\u0430] \u0415\u0433\u043E <em>(asya)</em> \u015Bakti-s, \u0438\u043B\u0438 \u0441\u0438\u043B\u044B --\u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0430\u0441\u043F\u0435\u043A\u0442\u044B, \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u044B\u0435 \u015Aakti-- <em>(\u015Baktaya\u1E25)</em> [\u2014 \u044D\u0442\u043E] \u0432\u0435\u0441\u044C <em>(k\u1E5Btsnam)</em> \u043C\u0438\u0440 <em>(jagat... iti)</em>&quot;||</p></blockquote><p>||8||</p><hr><ol start="2"><li><p>\u0418 \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u0432\u0441\u0435 \u044D\u0442\u043E \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E\u0435 \u043E\u043F\u0438\u0441\u0430\u043D\u0438\u0435 \u0435\u0441\u0442\u044C \u043D\u0435 \u0447\u0442\u043E \u0438\u043D\u043E\u0435, \u043A\u0430\u043A \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u015Aivavy\u0101pti, \u043E \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0433\u043E\u0432\u043E\u0440\u0438\u043B\u043E\u0441\u044C \u0432 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043A \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0435\u043C\u0443 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0443.</p></li><li><p>\u041E\u0431\u044B\u0447\u043D\u044B\u0439 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043F\u043E\u043B\u0430\u0433\u0430\u0435\u0442, \u0447\u0442\u043E \u043E\u0431\u044A\u0435\u043A\u0442\u044B, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043E\u043D \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0441\u0432\u043E\u0438\u043C\u0438 \u0447\u0443\u0432\u0441\u0442\u0432\u0430\u043C\u0438, \u0441\u0432\u044F\u0437\u0430\u043D\u044B \u0442\u043E\u043B\u044C\u043A\u043E \u0441 \u0447\u0443\u0432\u0441\u0442\u0432\u0430\u043C\u0438, \u043C\u043E\u0437\u0433\u043E\u043C \u0438 \u0442.\u0434. \u041D\u043E \u0432 \u0433\u043B\u0430\u0437\u0430\u0445 \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E Yog\u012B, \u044D\u0442\u043E \u043D\u0435 \u0442\u0430\u043A, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442, \u0447\u0442\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0412\u0435\u0437\u0434\u0435\u0441\u0443\u0449\u0435\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430 \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0432 \u043B\u044E\u0431\u043E\u0439 \u0432\u0435\u0449\u0438, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u044F\u0442\u0430 \u0438\u043C. \u0422\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435 \u043A\u0430\u043A \u0437\u0435\u0440\u043A\u0430\u043B\u043E, \u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0449\u0435\u0435 \u043E\u0442\u0440\u0430\u0436\u0435\u043D\u0438\u044F \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432, \u043D\u0435 \u043E\u0442\u043B\u0438\u0447\u0430\u0435\u0442\u0441\u044F \u043E\u0442 \u044D\u0442\u0438\u0445 \u043E\u0442\u0440\u0430\u0436\u0435\u043D\u0438\u0439, \u0442\u0430\u043A\u0436\u0435, \u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442, \u0447\u0442\u043E \u0432\u0441\u0435, \u0447\u0442\u043E \u043E\u043D \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0441\u0432\u043E\u0438\u043C\u0438 \u0447\u0443\u0432\u0441\u0442\u0432\u0430\u043C\u0438, \u2014 \u044D\u0442\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u0411\u043E\u0433. \u0421\u0443\u0431\u044A\u0435\u043A\u0442 (\u0411\u043E\u0433) \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u043A\u0430\u043A \u0432\u0441\u0435 \u044D\u0442\u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u044B \u0432\u043E\u043A\u0440\u0443\u0433, \u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A \u0433\u043E\u043B\u0443\u0431\u043E\u0439, \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435 \u0438 \u0442.\u0434. \u0418 \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u0438 \u0432\u0435\u0449\u0438 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u0443\u044E\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C, \u0442\u043E \u0447\u0435\u0440\u0435\u0437 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u0441\u0432\u043E\u0435\u0433\u043E \u0443\u043C\u0430 \u0432 \u044D\u0442\u043E\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u0435 (\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0438), \u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 Bharit\u0101tm\u0101, \u0438\u043B\u0438 &quot;\u0422\u043E\u0433\u043E, \u0447\u044C\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u043B\u043D\u043E\u0439&quot; (\u0442.\u0435. Parabhairava, \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0430). \u0421\u0434\u0435\u043B\u0430\u0432 \u044D\u0442\u043E, \u043E\u043D \u043D\u0430\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u043E\u043B\u043D\u043E\u0442\u044B/\u0438\u0437\u043E\u0431\u0438\u043B\u0438\u044F. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435.</p></li></ol></div><div class="stanza"><a href="#s3.9" id="s3.9" class="num">3.9</a><div class="sans"><p>\u0908\u0926\u0943\u0936\u0936\u094D\u091A\u093E\u092F\u0902 \u0938\u0930\u094D\u0935\u0926\u093E \u0938\u094D\u0935\u0938\u094D\u0935\u0930\u0942\u092A\u0935\u093F\u092E\u0930\u094D\u0936\u093E\u0935\u093F\u0937\u094D\u091F\u0903\u2014</p><blockquote><p><strong>\u0928\u0930\u094D\u0924\u0915 \u0906\u0924\u094D\u092E\u093E\u0965\u096F\u0965</strong></p></blockquote><p>\u0928\u0943\u0924\u094D\u092F\u0924\u094D\u092F\u0928\u094D\u0924\u0930\u094D\u0935\u093F\u0917\u0942\u0939\u093F\u0924\u0938\u094D\u0935\u0938\u094D\u0935\u0930\u0942\u092A\u093E\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u092E\u0942\u0932\u0902 \u0924\u0924\u094D\u0924\u091C\u094D\u091C\u093E\u0917\u0930\u093E\u0926\u093F\u0928\u093E\u0928\u093E\u092D\u0942\u092E\u093F\u0915\u093E\u092A\u094D\u0930\u092A\u091E\u094D\u091A\u0902 \u0938\u094D\u0935\u092A\u0930\u093F\u0938\u094D\u092A\u0928\u094D\u0926\u0932\u0940\u0932\u092F\u0948\u0935 \u0938\u094D\u0935\u092D\u093F\u0924\u094D\u0924\u094C \u092A\u094D\u0930\u0915\u091F\u092F\u0924\u0940\u0924\u093F \u0928\u0930\u094D\u0924\u0915 \u0906\u0924\u094D\u092E\u093E\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0928\u0948\u0936\u094D\u0935\u093E\u0938\u0926\u0947\u0935\u0940\u092E\u0939\u0947\u0936\u094D\u0935\u0930\u0928\u0930\u094D\u0924\u0915\u093E\u0916\u094D\u092F\u0947 \u0938\u092A\u094D\u0924\u092E\u092A\u091F\u0932\u0947 \u0926\u0947\u0935\u0940\u0915\u0943\u0924\u0938\u094D\u0924\u0935\u0947</p><blockquote><p>\u0924\u094D\u0935\u092E\u0947\u0915\u093E\u0902\u0936\u0947\u0928\u093E\u0928\u094D\u0924\u0930\u093E\u0924\u094D\u092E\u093E \u0928\u0930\u094D\u0924\u0915\u0903 \u0915\u094B\u0936\u0930\u0915\u094D\u0937\u093F\u0924\u093E\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u092D\u091F\u094D\u091F\u0936\u094D\u0930\u0940\u0928\u093E\u0930\u093E\u092F\u0923\u0947\u0928\u093E\u092A\u093F</p><blockquote><p>\u0935\u093F\u0938\u0943\u0937\u094D\u091F\u093E\u0936\u0947\u0937\u0938\u0926\u094D\u092C\u0940\u091C\u0917\u0930\u094D\u092D\u0902 \u0924\u094D\u0930\u0948\u0932\u094B\u0915\u094D\u092F\u0928\u093E\u091F\u0915\u092E\u094D\u0964<br> \u092A\u094D\u0930\u0938\u094D\u0924\u093E\u0935\u094D\u092F \u0939\u0930 \u0938\u0902\u0939\u0930\u094D\u0924\u0941\u0902 \u0924\u094D\u0935\u0924\u094D\u0924\u0903 \u0915\u094B\u093D\u0928\u094D\u092F\u0903 \u0915\u0935\u093F\u0903 \u0915\u094D\u0937\u092E\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0938\u0930\u094D\u0935\u093E\u0917\u092E\u094B\u092A\u0928\u093F\u0937\u0926\u093F \u0936\u094D\u0930\u0940\u092A\u094D\u0930\u0924\u094D\u092F\u092D\u093F\u091C\u094D\u091E\u093E\u092F\u093E\u092E\u094D</p><blockquote><p>\u0938\u0902\u0938\u093E\u0930\u0928\u093E\u091F\u094D\u092F\u092A\u094D\u0930\u0935\u0930\u094D\u0924\u092F\u093F\u0924\u093E \u0938\u0941\u092A\u094D\u0924\u0947 \u091C\u0917\u0924\u093F \u091C\u093E\u0917\u0930\u0942\u0915 \u090F\u0915 \u090F\u0935 \u092A\u0930\u092E\u0947\u0936\u094D\u0935\u0930\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u096F\u0965</p></div><hr><div class="trans"><p>\u012Ad\u1E5B\u015Ba\u015Bc\u0101ya\u1E41 sarvad\u0101 svasvar\u016Bpavimar\u015B\u0101vi\u1E63\u1E6Da\u1E25\u2014</p><blockquote><p><strong>Nartaka \u0101tm\u0101||9||</strong></p></blockquote><p>N\u1E5Btyatyantarvig\u016Bhitasvasvar\u016Bp\u0101va\u1E63\u1E6Dambham\u016Bla\u1E41 tattajj\u0101gar\u0101din\u0101n\u0101bh\u016Bmik\u0101prapa\xF1ca\u1E41 svaparispandal\u012Blayaiva svabhittau praka\u1E6Dayat\u012Bti nartaka \u0101tm\u0101| Tadukta\u1E41 \u015Br\u012Bnai\u015Bv\u0101sadev\u012Bmahe\u015Bvaranartak\u0101khye saptamapa\u1E6Dale dev\u012Bk\u1E5Btastave</p><blockquote><p>Tvamek\u0101\u1E41\u015Ben\u0101ntar\u0101tm\u0101 nartaka\u1E25 ko\u015Barak\u1E63it\u0101||</p></blockquote><p>iti| Bha\u1E6D\u1E6Da\u015Br\u012Bn\u0101r\u0101ya\u1E47en\u0101pi</p><blockquote><p>Vis\u1E5B\u1E63\u1E6D\u0101\u015Be\u1E63asadb\u012Bjagarbha\u1E41 trailokyan\u0101\u1E6Dakam|<br> Prast\u0101vya hara sa\u1E41hartu\u1E41 tvatta\u1E25 ko&#39;nya\u1E25 kavi\u1E25 k\u1E63ama\u1E25||</p></blockquote><p>iti| Sarv\u0101gamopani\u1E63adi \u015Br\u012Bpratyabhij\xF1\u0101y\u0101m</p><blockquote><p>Sa\u1E41s\u0101ran\u0101\u1E6Dyapravartayit\u0101 supte jagati j\u0101gar\u016Bka eka eva parame\u015Bvara\u1E25||</p></blockquote><p>iti||9||</p></div><hr><p>\u0418 <em>(ca)</em> \u044D\u0442\u043E\u0442 [Yog\u012B] <em>(ayam)</em>, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0439 \u0442\u0430\u043A\u0438\u043C\u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430\u043C\u0438 <em>(\u012Bd\u1E5B\u015Ba\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0432\u0441\u0435\u0433\u0434\u0430 <em>(sarvad\u0101)</em> \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u043D\u044B\u043C <em>(\u0101vi\u1E63\u1E6Da\u1E25)</em> \u0432 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(vimar\u015Ba)</em> \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-r\u016Bpa)</em>\u2014</p><blockquote><p><strong>[\u042D\u0442\u043E\u0442 \u0441\u0430\u043C\u044B\u0439 Yog\u012B \u0435\u0441\u0442\u044C] \u0412\u044B\u0441\u0448\u0435\u0435 \u042F <em>(\u0101tm\u0101)</em> [\u0432 \u0432\u0438\u0434\u0435 \u043F\u0440\u043E\u0441\u0442\u043E] \u0442\u0430\u043D\u0446\u0443\u044E\u0449\u0435\u0433\u043E \u0430\u043A\u0442\u0435\u0440\u0430 <em>(nartaka\u1E25)</em>||9||</strong></p></blockquote><p>\u041E\u043D \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u0435\u0442 \u0438 \u0442\u0430\u043D\u0446\u0443\u0435\u0442 <em>(n\u1E5Btyati)</em>, \u0442.\u0435. \u0447\u0435\u0440\u0435\u0437 \u0438\u0433\u0440\u0443 <em>(l\u012Blay\u0101 eva)</em> \u0441\u0432\u043E\u0438\u0445 <em>(sva)</em> \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0439 <em>(parispanda)</em> \u043E\u043D \u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0438\u0440\u0443\u0435\u0442 <em>(praka\u1E6Dayati)</em> \u043D\u0430 \u0441\u0432\u043E\u0435\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u044D\u043A\u0440\u0430\u043D\u0435 --\u0442.\u0435. \u044D\u043A\u0440\u0430\u043D\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(sva-bhittau)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(prapa\xF1cam)</em> \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 <em>(n\u0101n\u0101)</em> \u0440\u043E\u043B\u0435\u0439 <em>(bh\u016Bmik\u0101)</em> \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 <em>(tad-tad)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(j\u0101gar\u0101)</em> \u0438 \u0442.\u0434. <em>(\u0101di)</em> --\u0442.\u0435. \u0441\u043D\u0430 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430--. [\u042D\u0442\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 \u0440\u043E\u043B\u0435\u0439] \u0438\u043C\u0435\u0435\u0442 \u0441\u0432\u043E\u0438\u043C \u043A\u043E\u0440\u043D\u0435\u043C --\u0442.\u0435. \u0431\u0430\u0437\u0438\u0440\u0443\u0435\u0442\u0441\u044F-- <em>(ava\u1E63\u1E6Dambha-m\u016Blam)</em> \u0435\u0433\u043E <em>(sva)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(sva-r\u016Bpa)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0441\u043E\u043A\u0440\u044B\u0442\u0430 <em>(vig\u016Bhita)</em> \u0432\u043D\u0443\u0442\u0440\u0438 <em>(antar)</em>. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(iti)</em>, [\u043E\u043D \u0435\u0441\u0442\u044C] \u0412\u044B\u0441\u0448\u0435\u0435 \u042F <em>(\u0101tm\u0101)</em> [\u0432 \u0432\u0438\u0434\u0435 \u043F\u0440\u043E\u0441\u0442\u043E] \u0442\u0430\u043D\u0446\u0443\u044E\u0449\u0435\u0433\u043E \u0430\u043A\u0442\u0435\u0440\u0430 <em>(nartaka\u1E25)</em>|</p><p>\u041E\u0431 \u044D\u0442\u043E\u043C <em>(tad)</em> \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u043E <em>(uktam)</em> \u0432 \u0432\u043E\u0441\u0445\u0432\u0430\u043B\u044F\u044E\u0449\u0435\u0439 \u043C\u043E\u043B\u0438\u0442\u0432\u0435 <em>(stave)</em>, \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u043E\u0439 <em>(k\u1E5Bta\u1E25)</em> \u0411\u043E\u0433\u0438\u043D\u0435\u0439 <em>(dev\u012B)</em> \u0432 \u0441\u0435\u0434\u044C\u043C\u043E\u0439 \u0433\u043B\u0430\u0432\u0435 <em>(saptama-pa\u1E6Dale)</em> \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u0433\u043E Nai\u015Bv\u0101satantra <em>(\u015Br\u012B-nai\u015Bv\u0101sa)</em>, \u043E\u0437\u0430\u0433\u043B\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u0439 <em>(\u0101khye)</em> &quot;\u0411\u043E\u0433\u0438\u043D\u044F <em>(dev\u012B)</em> [\u0438] \u0412\u0435\u043B\u0438\u043A\u0438\u0439 <em>(mah\u0101)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u044C <em>(\u012B\u015Bvara)</em> \u043A\u0430\u043A \u0442\u0430\u043D\u0446\u0443\u044E\u0449\u0438\u0439 \u0430\u043A\u0442\u0435\u0440 <em>(nartaka)</em>&quot;:</p><blockquote><p>&quot;\u0422\u044B <em>(tvam)</em>, \u0432 \u043E\u0434\u043D\u043E\u043C \u0430\u0441\u043F\u0435\u043A\u0442\u0435 <em>(ek\u0101\u1E41\u015Bena)</em>, [\u0435\u0441\u0442\u044C] \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 <em>(antar)</em> \u044F <em>(\u0101tm\u0101)</em>, \u0442\u0430\u043D\u0446\u0443\u044E\u0449\u0438\u0439 \u0430\u043A\u0442\u0435\u0440 <em>(nartaka\u1E25)</em>, [\u043D\u043E \u0432 \u0434\u0440\u0443\u0433\u043E\u043C \u0430\u0441\u043F\u0435\u043A\u0442\u0435, \u0422\u044B \u2014 ] \u0437\u0430\u0449\u0438\u0442\u043D\u0438\u043A <em>(rak\u1E63it\u0101)</em> \u0421\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B \u043A\u0430\u043A \u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u043E <em>(ko\u015Ba... iti)</em><sup>1</sup>&quot;||</p></blockquote><p>[\u042D\u0442\u043E] \u0442\u0430\u043A\u0436\u0435 [\u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E] <em>(api)</em> \u0432 Bha\u1E6D\u1E6Da\u015Br\u012Bn\u0101r\u0101ya\u1E47a <em>(bha\u1E6D\u1E6Da\u015Br\u012Bn\u0101r\u0101ya\u1E47ena)</em> [\u0432 \u0435\u0433\u043E Stavacint\u0101ma\u1E47i]:</p><blockquote><p>&quot;[\u0422\u044B \u044F\u0432\u043B\u044F\u0435\u0448\u044C\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439] \u0414\u0440\u0430\u043C\u044B <em>(n\u0101\u1E6Dakam)</em> \u0442\u0440\u0435\u0445 \u043C\u0438\u0440\u043E\u0432 --\u043D\u0435\u0431\u0435\u0441, \u0430\u0434\u0430 \u0438 \u0437\u0435\u043C\u043B\u0438-- <em>(trailokya)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442 <em>(garbham)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0435 <em>(sat)</em> \u0441\u0435\u043C\u044F, \u0438\u043B\u0438 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A <em>(b\u012Bja)</em> \u0432\u0441\u0435\u0433\u043E <em>(a\u015Be\u1E63a)</em>, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043E <em>(vis\u1E5B\u1E63\u1E6Da)</em><sup>2</sup></p></blockquote><p>. [\u0422\u044B], \u043F\u0440\u0435\u0437\u0435\u043D\u0442\u0443\u044E\u0449\u0438\u0439 \u043F\u0440\u043E\u043B\u043E\u0433 [\u044D\u0442\u043E\u0439 \u0414\u0440\u0430\u043C\u044B] <em>(prast\u0101vya)</em>, \u041E Hara! --\u044D\u043F\u0438\u0442\u0435\u0442 \u015Aiva-- <em>(hara)</em>!, \u043A\u0430\u043A\u043E\u0439 <em>(ka\u1E25)</em> \u043F\u043E\u044D\u0442 <em>(kavi\u1E25)</em>, \u043A\u0440\u043E\u043C\u0435 \u0422\u0435\u0431\u044F \u0421\u0430\u043C\u043E\u0433\u043E <em>(tvatta\u1E25... anya\u1E25)</em>, \u043F\u043E\u0434\u0445\u043E\u0434\u0438\u0442 <em>(k\u1E63ama\u1E25)</em> \u0434\u043B\u044F \u0435\u0435 \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u044F <em>(sa\u1E41hartum... iti)</em><sup>3</sup>?&quot;||</p><p>[\u0418 \u0434\u0430\u0436\u0435] \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u0439 \u012A\u015Bvarapratyabhij\xF1\u0101 <em>(\u015Br\u012B-pratyabhij\xF1\u0101y\u0101m)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442 \u0441\u0435\u043A\u0440\u0435\u0442\u043D\u043E\u0435 \u0443\u0447\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u0445 \u0410\u0433\u0430\u043C (\u0100gama-s), \u0438\u043B\u0438 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u0445 \u041F\u0438\u0441\u0430\u043D\u0438\u0439 <em>(sarva-\u0101gama-upani\u1E63adi)</em>, [\u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u043F\u0440\u043E\u0447\u0435\u0441\u0442\u044C \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435]:</p><blockquote><p>&quot;\u041A\u043E\u0433\u0434\u0430 \u043C\u0438\u0440 \u0441\u043F\u0438\u0442 <em>(supte jagati)</em>, \u0442\u043E\u043B\u044C\u043A\u043E <em>(eka\u1E25 eva)</em> \u0412\u044B\u0441\u0448\u0438\u0439 <em>(parama)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u044C <em>(\u012B\u015Bvara\u1E25)</em>, \u0422\u043E\u0442, \u043A\u0442\u043E \u043F\u0440\u0438\u0432\u043E\u0434\u0438\u0442 \u0432 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 <em>(pravartayit\u0101)</em> \u0442\u0430\u043D\u0446\u0435\u0432\u0430\u043B\u044C\u043D\u0443\u044E \u0434\u0440\u0430\u043C\u0443 <em>(n\u0101\u1E6Dya)</em>, [\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0443\u044E \u043A\u0430\u043A] Sa\u1E41s\u0101ra --\u0442.\u0435. \u0422\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u044E, \u043F\u043E\u043B\u043D\u0443\u044E \u043C\u0443\u0447\u0435\u043D\u0438\u0439-- <em>(sa\u1E41s\u0101ra)</em>, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u043C <em>(j\u0101gar\u016Bka\u1E25... iti)</em>&quot;||</p></blockquote><p>||9||</p><hr><ol><li><p>\u0412 \u0415\u0433\u043E \u0430\u0441\u043F\u0435\u043A\u0442\u0435 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 \u0441\u0430\u043C\u043E\u0441\u0442\u0438 (antar\u0101tm\u0101), \u041E\u043D \u2014 \u0442\u0430\u043D\u0446\u0443\u044E\u0449\u0438\u0439 \u0430\u043A\u0442\u0435\u0440, \u043A\u0442\u043E \u0432 \u0441\u0438\u043B\u0443 \u0441\u0432\u043E\u0435\u0439 \u0441\u0432\u044F\u0437\u0438 \u0441 purya\u1E63\u1E6Daka (\u0442\u043E\u043D\u043A\u0438\u043C \u0442\u0435\u043B\u043E\u043C, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0438\u043C \u0438\u0437 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430, \u044D\u0433\u043E, \u0443\u043C\u0430 \u0438 \u0442\u043E\u043D\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432), \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D \u0442\u0435\u043D\u0434\u0435\u043D\u0446\u0438\u044F\u043C\u0438 (v\u0101san\u0101-s) \u0445\u043E\u0440\u043E\u0448\u0438\u0445 \u0438 \u043F\u043B\u043E\u0445\u0438\u0445 \u0434\u0435\u044F\u043D\u0438\u0439, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0442 \u0435\u0433\u043E \u0441\u043A\u0438\u0442\u0430\u0442\u044C\u0441\u044F \u043E\u0442 \u043E\u0434\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u044B \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F \u043A \u0434\u0440\u0443\u0433\u043E\u0439. \u0422\u043E \u0435\u0441\u0442\u044C \u043E\u043D \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u044B\u0435 \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0438\u0437-\u0437\u0430 \u044D\u0442\u0438\u0445 \u0442\u0435\u043D\u0434\u0435\u043D\u0446\u0438\u0439. \u041E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u043C \u0421\u0430\u043C\u0441\u0430\u0440\u044B (Sa\u1E41s\u0101ra), \u0438\u043B\u0438 \u0422\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u0438 (\u0442.\u0435. \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u0439). \u042D\u0442\u043E \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F &quot;\u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 \u044F (\u0441\u0430\u043C\u043E\u0441\u0442\u044C)&quot;, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u043E \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0432\u043D\u0443\u0442\u0440\u0438 \u0432\u043D\u0435\u0448\u043D\u0435\u0433\u043E \u044F (\u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0442\u0435\u043B\u0430). \u0412 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C, \u0441\u043B\u043E\u0432\u043E &quot;ko\u015Ba&quot; \u043D\u0435 \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043E \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u043A\u0430\u043A &quot;\u043E\u0431\u043E\u043B\u043E\u0447\u043A\u0430&quot;, \u0430 \u043A\u0430\u043A &quot; \u0938\u094D\u0935\u0938\u094D\u0935\u0930\u0942\u092A\u092A\u0930\u092E\u093E\u0924\u094D\u092E\u0924\u094D\u0935 &quot; - &quot;svasvar\u016Bpaparam\u0101tmatva&quot;, \u0438\u043B\u0438 &quot;\u0412\u0430\u0448\u0430 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u043A\u0430\u043A \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0430&quot;. \u0421\u0443\u043C\u043C\u0438\u0440\u0443\u044F \u044D\u0442\u043E, \u0412\u0435\u043B\u0438\u043A\u0438\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0438 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u043C, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u043C \u0441\u0432\u043E\u0438\u043C \u0442\u043E\u043D\u043A\u0438\u043C \u0442\u0435\u043B\u043E\u043C \u0438 \u0442.\u0434., \u0438 \u0412\u044B\u0441\u0448\u0438\u043C \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u043C, \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u043C \u0432 \u0421\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438. \u041E\u043D \u0437\u0430\u0449\u0438\u0449\u0430\u0435\u0442 \u0421\u0432\u043E\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u0432 \u0442\u043E\u043C \u0441\u043C\u044B\u0441\u043B\u0435, \u0447\u0442\u043E \u041E\u043D \u043D\u0435 \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u0435\u0442 \u043D\u0438\u0447\u0435\u043C\u0443 \u043A\u043E\u0441\u043D\u0443\u0442\u044C\u0441\u044F \u0435\u0435. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u041E\u043D, \u0432 \u0421\u0432\u043E\u0435\u0439 \u0441\u0430\u043C\u043E\u0439 \u0441\u043E\u043A\u0440\u043E\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438, \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u0432\u0441\u0435\u0433\u0434\u0430 \u0432\u043D\u0435 \u0432\u0441\u0435\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F, \u0432\u044B\u0437\u0432\u0430\u043D\u043D\u043E\u0433\u043E \u0415\u0433\u043E M\u0101y\u0101, \u0438\u043B\u0438 \u041D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435\u043C. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435.</p></li><li><p>\u0422\u0435\u0440\u043C\u0438\u043D &quot;b\u012Bja&quot; (\u0441\u0435\u043C\u044F, \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A) \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0437\u0434\u0435\u0441\u044C M\u0101y\u0101 \u0438 \u0435\u0435 \u043F\u043E\u0442\u043E\u043C\u0441\u0442\u0432\u043E (Prak\u1E5Bti, \u0438 \u0442.\u0434.), \u043D\u043E \u0432 \u0434\u0440\u0430\u043C\u0435, \u044D\u0442\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A \u0441\u044E\u0436\u0435\u0442\u0430&quot;. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u044D\u0442\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u044B \u0438\u043C\u0435\u0435\u0442 \u0434\u0432\u0430 \u0441\u043C\u044B\u0441\u043B\u0430, \u0441 \u043E\u0434\u043D\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B, M\u0101y\u0101 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u043C \u0432\u0441\u0435\u0433\u043E \u0441\u0443\u0449\u0435\u0433\u043E, \u0430 \u0441 \u0434\u0440\u0443\u0433\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B, \u041E\u043D\u0430 \u0442\u0430\u043A\u0436\u0435 \u0435\u0441\u0442\u044C \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A \u0441\u044E\u0436\u0435\u0442\u0430 \u044D\u0442\u043E\u0439 \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0439 \u0414\u0440\u0430\u043C\u044B. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435.</p></li><li><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u043D\u0430\u043F\u0438\u0441\u0430\u043B \u043F\u0440\u043E\u043B\u043E\u0433, \u0438\u043B\u0438 &quot;prast\u0101va&quot; \u044D\u0442\u043E\u0439 \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0439 \u0414\u0440\u0430\u043C\u044B, \u0442\u043E \u043A\u0442\u043E \u043A\u0440\u043E\u043C\u0435 \u041D\u0435\u0433\u043E \u0441\u0430\u043C\u043E\u0433\u043E \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u043D\u0430\u043F\u0438\u0441\u0430\u0442\u044C \u0435\u0435 &quot;sa\u1E41h\u0101ra&quot;, \u0438\u043B\u0438 \u0437\u0430\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435? \u041A\u043E\u0433\u0434\u0430 \u043E\u043D \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 \u0441\u0432\u043E\u044E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u0438, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0418\u0441\u0442\u0438\u043D\u0443, \u0447\u0442\u043E \u0432\u0441\u0435 \u0438 \u0432\u0441\u0435 \u0441\u0443\u0449\u0435\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0418\u043C, \u044D\u0442\u043E \u0438 \u0435\u0441\u0442\u044C \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u0435 \u0414\u0440\u0430\u043C\u044B. \u0422\u0430\u043A \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0441\u0438\u0442\u0435\u043C\u0435 \u0422\u0440\u0438\u043A\u0438, \u044D\u0442\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0415\u0433\u043E \u041C\u0438\u043B\u043E\u0441\u0442\u0438 \u0438 &quot;\u043D\u0438\u043A\u0430\u043A \u0438\u043D\u0430\u0447\u0435&quot; (\u0442.\u0435. \u0447\u0435\u0440\u0435\u0437 \u0443\u0441\u0438\u043B\u0438\u044F). \u041D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E \u0443\u0441\u0438\u043B\u0438\u044F \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0430 \u043C\u043E\u0433\u0443\u0442 \u043F\u0440\u0438\u0432\u0435\u0441\u0442\u0438 \u043A \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u043C\u0443 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u0435 (\u041E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435) \u0432\u0441\u0435\u0433\u0434\u0430 &quot;\u043F\u0438\u0448\u0435\u0442\u0441\u044F&quot; (\u043E\u0431\u0440\u0430\u0437\u043D\u043E \u0433\u043E\u0432\u043E\u0440\u044F) \u0442\u043E\u043B\u044C\u043A\u043E \u0418\u043C \u043E\u0434\u043D\u0438\u043C. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435.</p></li></ol><p>\u0414\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u0430\u044F \u0442\u043E\u043D\u043A\u043E\u0441\u0442\u044C: \u0422\u0435\u0440\u043C\u0438\u043D&quot;ka\u1E25&quot;, \u043A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E &quot;\u0447\u0442\u043E, \u043A\u0442\u043E&quot;, \u0442\u0430\u043A\u0436\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot; \u092A\u094D\u0930\u091C\u093E\u092A\u0924\u093F &quot; - &quot;Praj\u0101pati&quot; (\u0412\u043B\u0430\u0441\u0442\u0435\u043B\u0438\u043D \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F), \u0442.\u0435. \u0422\u043E\u0442, \u043A\u0442\u043E \u0441\u043E\u0442\u0432\u043E\u0440\u0438\u043B \u0436\u0438\u0432\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432. \u0422\u0435\u043C\u0430 Praj\u0101pati \u2014 \u043E\u0447\u0435\u043D\u044C \u0434\u043B\u0438\u043D\u043D\u0430\u044F \u0434\u043B\u044F \u044D\u0442\u043E\u0433\u043E \u043F\u043E\u044F\u0441\u043D\u0435\u043D\u0438\u044F. \u041F\u043E\u043A\u0430, \u043F\u0440\u043E\u0441\u0442\u043E \u043F\u043E\u0439\u043C\u0438\u0442\u0435, \u0447\u0442\u043E \u0435\u0441\u043B\u0438 \u044D\u0442\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0432\u043D\u0435\u0441\u0435\u043D\u043E \u0432 \u043F\u0435\u0440\u0435\u0432\u043E\u0434, \u0442\u043E \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u0442\u0432\u0438\u0441\u0442: &quot;[\u0413\u0434\u0435] \u0435\u0441\u0442\u044C Praj\u0101pati \u043A\u0440\u043E\u043C\u0435 \u0422\u0435\u0431\u044F \u0441\u0430\u043C\u043E\u0433\u043E...?&quot; \u041E\u0441\u0442\u0430\u043B\u044C\u043D\u043E\u0435, \u044F \u043D\u0430\u0434\u0435\u044E\u0441\u044C, \u043F\u043E\u043D\u044F\u0442\u043D\u043E.</p></div><p>:</p>',3),o=[p];function r(s,v,u,k,n,l){return m(),e("div",null,o)}var y=a(i,[["render",r]]);export{d as __pageData,y as default};
